  ('judicial-7acda994-moex-00074', 'judicial-7acda994', 'judicial-7acda994-moex-111-359207d9', 'sub-judicial-7acda994-06', NULL, 'single_choice', '承上題，下列選項最符合旨意的是：', '["透過自然休閒旅遊，可以拓展生態環境保育觀念", "推廣天人合一的信念，可強化生態環境保育觀念", "欠缺生態環境保育意識，導致稀有珍貴鳥類絕種", "保護候鳥重要棲地，可提升發展生態觀光的潛力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "6d205a249f8d", "answer_pdf_sha1": "40189eca7d37", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "104", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文、公文與測驗)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00075', 'judicial-7acda994', 'judicial-7acda994-moex-111-4bf6d96a', 'sub-judicial-7acda994-02', NULL, 'essay', '甲、乙公司簽訂專任委託銷售契約書（下稱系爭契約），約定由乙委託甲
銷售位於臺北市內湖區（管轄法院為臺灣士林地方法院）之不動產，依
據系爭契約第 16 條規定「雙方同意以房地產所在地之地方法院為第一
審管轄法院。」嗣後甲認為乙故意不與其覓得之對象簽約，向乙所在地
之臺灣臺北地方法院（下稱臺北地院）起訴請求乙給付服務報酬及違約
金，試問：本件房地係在臺北市內湖區，然原告卻向臺北地院起訴，本
件臺北地院對本件是否具有管轄權？理由為何？關於合意管轄之約款
是否屬於定型化契約條款？又當事人是否得主張不受該約款之拘束？
又當事人簽署契約中雖有合意管轄之規定，有那些例外規定可以主張不
受合意管轄條款拘束之情形？（30 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "a452741f78aa", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "104", "s": "0406", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00076', 'judicial-7acda994', 'judicial-7acda994-moex-111-4bf6d96a', 'sub-judicial-7acda994-02', NULL, 'essay', '甲因為與乙發生車禍事故，受有手臂挫傷之傷害，遂起訴請求乙賠償其
所受之損害。甲起訴時，考量裁判費的問題及證明其損害範圍之困難性，
遂先為一部請求，訴請被告乙給付新臺幣（下同）40 萬元。試附理由回
答：甲為一部請求，在法律上是否允許？法院應否請甲表明是否為全部
之請求？本件甲起訴時，法院應踐行之第一審訴訟程序為何種類型？於
進入訴訟程序前有無其他可由當事人自主解決紛爭之機制？倘本件甲
一開始一部請求之金額為100萬元時，法院應踐行之第一審訴訟程序是
否會有不同，理由為何？又法院審理期間，乙經合法通知未到庭亦未提
出書狀為答辯，甲遂表明追加請求精神慰撫金 100 萬元並聲請一造辯論
判決，法院是否應判決甲全部勝訴？又關於此判決有無依職權宣告假執
行之必要？（40分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "a452741f78aa", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "104", "s": "0406", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00077', 'judicial-7acda994', 'judicial-7acda994-moex-111-4bf6d96a', 'sub-judicial-7acda994-02', NULL, 'essay', '原告甲與被告乙於第一審訴訟程序期間，因為兩造有商談和解之可能，
兩造向法院陳明合意停止訴訟程序。嗣後因無法達成和解，甲遂具狀向
法院聲請續行訴訟程序，法院指定民國 111 年 6 月 30 日為言詞辯論期
日，然該期日甲經合法通知未到場，乙並未聲請一造辯論判決，反而拒
絕辯論。試問：乙為前揭行為之訴訟法上效果為何？法院如果因為訴訟
進行的結果已有心證，為了結案，可否依職權為一造辯論判決？法院因
乙拒絕辯論後，應如何處理後續之訴訟程序？（30 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "a452741f78aa", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "104", "s": "0406", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00078', 'judicial-7acda994', 'judicial-7acda994-moex-111-9b7ab1bb', 'sub-judicial-7acda994-03', NULL, 'essay', '甲為乙之公司主管，某日甲因工作問題斥責乙。同單位之丙見狀，便唆
使乙對甲報復。經丙之唆使，乙起了報復之心，便破壞甲騎乘之機車，
致使甲騎車下班時發生車禍，甲之機車全毀，人亦摔傷住院三個月方痊
癒出院。車禍發生當天，乙即深感後悔，趕到醫院向甲表示歉意，並坦
白說明甲之機車是其所破壞，但乙未說出丙唆使之情事。甲念乙之家境
清寒，故未向乙請求損害賠償。事隔三年，甲方得知丙唆使乙破壞其機
車之情事。試問：甲對丙是否仍得請求損害賠償？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "a9f74b4b810d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "104", "s": "0401", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00079', 'judicial-7acda994', 'judicial-7acda994-moex-111-9b7ab1bb', 'sub-judicial-7acda994-03', NULL, 'essay', '甲與乙簽訂不動產買賣契約書，將其所有 A地號土地出賣予乙，契約約
定︰「本買賣不動產移轉登記時，關於取得不動產權利名義人，得由乙
方（即買受人乙）自由選擇或指定之。」嗣後甲受乙之指定，將A地號
土地移轉登記予丙。然因乙逾期未付清價款，經甲定期催告未果，甲乃
解除契約並沒收乙已付之價金。甲主張原買賣契約應屬無效，丙乃無法
律上原因取得 A地號土地所有權致其受損害，故成立不當得利，因而請
求丙應將 A 地號土地所有權移轉登記予甲。試問：甲之主張是否有理
由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "a9f74b4b810d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "104", "s": "0401", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00080', 'judicial-7acda994', 'judicial-7acda994-moex-111-9b7ab1bb', 'sub-judicial-7acda994-03', NULL, 'essay', '甲向乙承租有三間辦公室之 A屋，未徵得乙同意下，甲將其中一間辦公
室出租給丙。嗣後乙發現甲與丙間上述租賃情事，主張其與丙間並無任
何契約關係存在，丙係無權占有，便請求丙遷出該辦公室並返還給乙。
試問：乙之請求是否有理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "a9f74b4b810d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "104", "s": "0401", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00081', 'judicial-7acda994', 'judicial-7acda994-moex-111-9b7ab1bb', 'sub-judicial-7acda994-03', NULL, 'essay', '甲之配偶於民國（下同）103 年死亡，甲則於 105 年 8 月死亡，遺有不
動產（下稱系爭不動產）一筆。乙、丙係甲之婚生子女，而丙已於 104
年死亡，丙之婚生子女為丁。乙與丁繼承系爭不動產並於 105 年 10 月
登記為系爭不動產之公同共有人。嗣後，戊另案訴請丙死後認領之判決
於 107 年 1月確定，確認戊為丙之非婚生子女，丙應認領戊。戊乃以繼
承為原因，請求登記為該系爭不動產之公同共有人之一。試問：戊之主
張是否有理？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "a9f74b4b810d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "104", "s": "0401", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00082', 'judicial-7acda994', 'judicial-7acda994-moex-111-3d2b73b6', 'sub-judicial-7acda994-07', NULL, 'single_choice', '依司法院大法官解釋，下列何者尚不違背法治國家正當法律程序之要求？', '["以行政文書依法寄存送達完畢時，作為發生送達效力之時點", "稽徵稅捐所發之各種文書，規定對公同共有人中之一人為送達者，其效力及於全體", "於自辦市地重劃案件，未設置適當組織，以審議關於市地重劃範圍之核定程序", "於都市更新程序，未確保利害關係人知悉相關資訊及適時陳述意見之機會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "104", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00083', 'judicial-7acda994', 'judicial-7acda994-moex-111-3d2b73b6', 'sub-judicial-7acda994-07', NULL, 'single_choice', '依憲法增修條文規定，下列何者有權提出憲法修正案？', '["自由地區選舉人連署", "國民大會", "總統", "立法院"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:30+00:00", "source_pdf_sha1": "7e65358788c6", "answer_pdf_sha1": "8d25a23b5974", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "104", "s": "0315", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL)
